import{_ as t,O as l,H as e,f as i,b as n,j as a,k as o,i as r}from"./chunks/framework.Pt2pSV98.js";const x=JSON.parse('{"title":"Prompt 优化前后对比","description":"同一个需求，不同的 Prompt 写法能带来多大的输出差距——四个实战场景的前后对比","frontmatter":{"title":"Prompt 优化前后对比","description":"同一个需求，不同的 Prompt 写法能带来多大的输出差距——四个实战场景的前后对比","difficulty":"beginner"},"headers":[],"relativePath":"prompts/prompt-comparison.md","filePath":"prompts/prompt-comparison.md"}'),c={name:"prompts/prompt-comparison.md"},d={id:"prompt-优化前后对比",tabindex:"-1"};function h(m,s,g,u,b,P){const p=l("DifficultyBadge");return e(),i("div",null,[n("h1",d,[s[0]||(s[0]=a("Prompt 优化前后对比 ",-1)),o(p,{level:"beginner"}),s[1]||(s[1]=a()),s[2]||(s[2]=n("a",{class:"header-anchor",href:"#prompt-优化前后对比","aria-label":'Permalink to "Prompt 优化前后对比 <DifficultyBadge level="beginner" />"'},"​",-1))]),s[3]||(s[3]=r(`<p>同一个需求，不同的 Prompt 写法，AI 的输出质量可能天差地别。本文通过四个实战场景的对比，直观展示「模糊指令」和「精准指令」之间的差距，并总结优化 Prompt 的核心原则。</p><hr><h2 id="场景一-写文案" tabindex="-1">场景一：写文案 <a class="header-anchor" href="#场景一-写文案" aria-label="Permalink to &quot;场景一：写文案&quot;">​</a></h2><p>目标：为一款新上市的蓝牙耳机写一段产品介绍。</p><table tabindex="0"><thead><tr><th>不好的 Prompt</th><th>好的 Prompt</th><th>差距原因</th></tr></thead><tbody><tr><td><code>帮我写一段蓝牙耳机的产品介绍</code></td><td>见下方完整 Prompt</td><td>没有角色、没有受众、没有格式要求，AI 只能猜</td></tr></tbody></table><p><strong>好的 Prompt</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一名消费电子产品的文案策划，擅长用场景化的语言打动年轻消费者。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>为一款「超长续航蓝牙耳机」撰写电商详情页的产品介绍。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 产品信息</span></span>
<span class="line"><span>- 产品名：AirBeat Pro</span></span>
<span class="line"><span>- 核心卖点：续航 40 小时、主动降噪、IPX5 防水、Type-C 快充</span></span>
<span class="line"><span>- 目标用户：25-35 岁通勤白领</span></span>
<span class="line"><span>- 价格：¥399</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 要求</span></span>
<span class="line"><span>1. 开场用一个通勤场景切入，引发共鸣</span></span>
<span class="line"><span>2. 介绍每个卖点时配一个使用场景（不是参数罗列）</span></span>
<span class="line"><span>3. 语气：年轻、有质感、不过于热烈</span></span>
<span class="line"><span>4. 篇幅：300 字左右</span></span>
<span class="line"><span>5. 结尾加一个行动号召</span></span></code></pre></div><p><strong>效果差距</strong>：</p><ul><li>不好的 Prompt → AI 会输出一段泛泛而谈的「蓝牙耳机很好用」式文案，放任何产品上都适用</li><li>好的 Prompt → AI 会输出有场景、有画面感、直击目标用户痛点的文案</li></ul><hr><h2 id="场景二-代码生成" tabindex="-1">场景二：代码生成 <a class="header-anchor" href="#场景二-代码生成" aria-label="Permalink to &quot;场景二：代码生成&quot;">​</a></h2><p>目标：写一个 Python 函数来解析 CSV 文件中的日期列，统计每月的记录数量。</p><table tabindex="0"><thead><tr><th>不好的 Prompt</th><th>好的 Prompt</th><th>差距原因</th></tr></thead><tbody><tr><td><code>写一个 Python 函数，处理 CSV 文件的日期</code></td><td>见下方完整 Prompt</td><td>缺少输入格式、边界条件、错误处理和输出结构</td></tr></tbody></table><p><strong>好的 Prompt</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>写一个 Python 函数 \`count_records_by_month(csv_path, date_column)\`，具体要求：</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输入</span></span>
<span class="line"><span>- csv_path: CSV 文件路径</span></span>
<span class="line"><span>- date_column: 日期列的名称</span></span>
<span class="line"><span>- 日期格式可能为以下几种之一：&#39;2024-01-15&#39;, &#39;2024/01/15&#39;, &#39;01/15/2024&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 处理逻辑</span></span>
<span class="line"><span>1. 自动识别日期列的格式（从以上三种中匹配）</span></span>
<span class="line"><span>2. 跳过空行和无效日期</span></span>
<span class="line"><span>3. 按「年-月」分组统计记录数量</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出</span></span>
<span class="line"><span>- 返回一个 dict，格式：{&#39;2024-01&#39;: 42, &#39;2024-02&#39;: 38, ...}</span></span>
<span class="line"><span>- 按月份升序排列</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 错误处理</span></span>
<span class="line"><span>- 文件不存在时抛出 FileNotFoundError</span></span>
<span class="line"><span>- 日期列不存在时抛出 ValueError</span></span>
<span class="line"><span>- 无效日期行打印 warning 后跳过，不中断整体处理</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 代码风格</span></span>
<span class="line"><span>- 使用类型注解</span></span>
<span class="line"><span>- 添加 docstring</span></span>
<span class="line"><span>- 关键步骤加注释</span></span></code></pre></div><p><strong>效果差距</strong>：</p><ul><li>不好的 Prompt → AI 可能随便写一个日期解析函数，不会考虑多种格式，也不处理异常</li><li>好的 Prompt → AI 生成的函数可以直接用于生产环境，输入输出明确，边界情况都覆盖</li></ul><hr><h2 id="场景三-翻译" tabindex="-1">场景三：翻译 <a class="header-anchor" href="#场景三-翻译" aria-label="Permalink to &quot;场景三：翻译&quot;">​</a></h2><p>目标：将一篇关于机器学习的中文博客翻译成英文。</p><table tabindex="0"><thead><tr><th>不好的 Prompt</th><th>好的 Prompt</th><th>差距原因</th></tr></thead><tbody><tr><td><code>翻译这段文字成英文</code></td><td>见下方完整 Prompt</td><td>没有指定领域、风格和术语表，翻译结果可能不专业</td></tr></tbody></table><p><strong>好的 Prompt</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请将以下中文技术文章翻译成英文。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 翻译要求</span></span>
<span class="line"><span>- 领域：机器学习 / 深度学习</span></span>
<span class="line"><span>- 风格：技术博客风格，专业但不学究气</span></span>
<span class="line"><span>- 术语表：</span></span>
<span class="line"><span>  - 反向传播 → backpropagation</span></span>
<span class="line"><span>  - 梯度下降 → gradient descent</span></span>
<span class="line"><span>  - 过拟合 → overfitting</span></span>
<span class="line"><span>  - 特征工程 → feature engineering</span></span>
<span class="line"><span>- 中文特有的表达（如「炼丹」指模型调参）用意译而非直译，并加简短注释</span></span>
<span class="line"><span>- 保留原文的 Markdown 格式和代码块</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原文：</span></span>
<span class="line"><span>[粘贴原文]</span></span></code></pre></div><p><strong>效果差距</strong>：</p><ul><li>不好的 Prompt → AI 可能把「反向传播」直译为 &quot;reverse propagation&quot;，把「炼丹」翻译成 &quot;alchemy&quot;</li><li>好的 Prompt → AI 能理解中文技术社区的行话，给出专业且地道的英文技术翻译</li></ul><hr><h2 id="场景四-分析报告" tabindex="-1">场景四：分析报告 <a class="header-anchor" href="#场景四-分析报告" aria-label="Permalink to &quot;场景四：分析报告&quot;">​</a></h2><p>目标：对某季度的销售数据做一个分析报告。</p><table tabindex="0"><thead><tr><th>不好的 Prompt</th><th>好的 Prompt</th><th>差距原因</th></tr></thead><tbody><tr><td><code>分析一下上个季度的销售数据</code></td><td>见下方完整 Prompt</td><td>没有给出分析框架、维度、格式要求和数据范围</td></tr></tbody></table><p><strong>好的 Prompt</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请对 2024 年 Q1 销售数据进行分析，生成一份结构化报告。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 数据</span></span>
<span class="line"><span>[粘贴数据，或描述数据结构：包含字段 日期、产品类别、销售额、订单量、地区]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 分析框架</span></span>
<span class="line"><span>请按以下维度逐一分析：</span></span>
<span class="line"><span>1. **总体概览**：总销售额、总订单量、同比/环比增长率</span></span>
<span class="line"><span>2. **产品分析**：各类别销售额占比、增长最快的 TOP 3、下滑最多的类别</span></span>
<span class="line"><span>3. **地区分析**：各地区销售额排名、增长潜力地区</span></span>
<span class="line"><span>4. **时间趋势**：月度趋势、周度波动、是否有明显的峰值和低谷</span></span>
<span class="line"><span>5. **问题与建议**：基于数据发现的问题 + 3 条可执行的改进建议</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>- 每个维度用二级标题</span></span>
<span class="line"><span>- 关键数据用加粗标注</span></span>
<span class="line"><span>- 趋势描述用简洁的 Markdown 表格</span></span>
<span class="line"><span>- 结论部分用段落文字总结</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 示例</span></span>
<span class="line"><span>类似这种结构：</span></span>
<span class="line"><span>## 总体概览</span></span>
<span class="line"><span>Q1 总销售额为 **350 万元**，同比增长 **22%**，环比增长 **8%**。</span></span>
<span class="line"><span>其中 3 月贡献了 42% 的销售额，与季节性促销活动高度相关。</span></span></code></pre></div><p><strong>效果差距</strong>：</p><ul><li>不好的 Prompt → AI 可能输出一段笼统的「销售额不错，建议加强营销」式的废话</li><li>好的 Prompt → AI 会输出一份有数据支撑、有结构、有可执行建议的专业分析报告</li></ul><hr><h2 id="优化-prompt-的核心原则" tabindex="-1">优化 Prompt 的核心原则 <a class="header-anchor" href="#优化-prompt-的核心原则" aria-label="Permalink to &quot;优化 Prompt 的核心原则&quot;">​</a></h2><p>从以上四个场景的对比中，可以提炼出写出好 Prompt 的五个核心原则：</p><ol><li><p><strong>给角色</strong>：告诉 AI「你是谁」，它会自动调用该角色的知识和语言风格</p><ul><li>❌ <code>写一段文案</code></li><li>✅ <code>你是一名消费电子文案策划，目标用户是……</code></li></ul></li><li><p><strong>给结构</strong>：告诉 AI「按什么框架来组织」</p><ul><li>❌ <code>分析一下</code></li><li>✅ <code>请按以下维度分析：1. 总体概览 2. 产品分析 3. 问题与建议</code></li></ul></li><li><p><strong>给格式</strong>：告诉 AI「输出成什么样」</p><ul><li>❌ <code>翻译这段</code></li><li>✅ <code>用 Markdown 表格对比，关键术语保留英文后加中文注释</code></li></ul></li><li><p><strong>给示例</strong>：用 Few-Shot 让 AI 理解你想要的风格和深度</p><ul><li>❌ 只有一个模糊指令</li><li>✅ 给出一个期望输出的样例</li></ul></li><li><p><strong>给边界</strong>：告诉 AI「什么不能做」「遇到不确定怎么办」</p><ul><li>❌ 让 AI 自己猜</li><li>✅ <code>如果不确定术语翻译，标注 [待确认] 而非随意翻译</code></li></ul></li></ol><p><strong>记住一句话</strong>：AI 不会读心。你给的信息越多、越结构化、越具体，它的输出就越接近你的预期。</p>`,38))])}const y=t(c,[["render",h]]);export{x as __pageData,y as default};
